INSERT INTO public.photos VALUES (23476, 'La Aljaferâ”œÂ¡a 1986', 'Foto: Juan Gonzâ”œÃ­lez Misis. 10 de mayo de 1986. El prâ”œÂ¡ncipe Felipe de Borbâ”œâ”‚n se afana en la colocaciâ”œâ”‚n de la primera piedra de las obras de acondicionamiento del palacio de la Aljaferâ”œÂ¡a como futura sede de las Cortes de Aragâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 1986, 1986, 1986, 'Anos 80', 'DELICIAS', 41.65648500, -0.89700700, '0101000020E6100000ED0E290648B4ECBF44A852B307D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33499313435.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33499313435.webp', 'https://www.flickr.com/photos/zaragozaantigua/33499313435/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23696, 'Carmelitas Descalzos 1923', 'En 1835, los procesos desamortizadores desamortizaron a los PP. Carmelitas Descalzos del Convento de San Josâ”œÂ®, en el que llevaban casi desde 1594. Volvieron en febrero de 1897, a la casa-asilo para sacerdotes que el Arzobispo les prestâ”œâ”‚ en el barrio de Delicias. Allâ”œÂ¡ estuvieron hasta enero de 1946, en que se trasladaron a la nueva parroquia de la calle San Juan de la Cruz. Este edificio fue luego ocupado por el colegio de las Hijas de San Josâ”œÂ® y la escuela de San Valero hasta su derribo en los aâ”œâ–’os 80. En la imagen, la Casa-Asilo prestada para convento carmelita, sita en las inmediaciones del cuartel de la Aljaferâ”œÂ¡a, entre la carretera de Madrid y las vâ”œÂ¡as del ferrocarril, junto al Barrio de la Explanada. Su fachada mira hacia la Aljaferâ”œÂ¡a.', 1923, 1923, 1923, 'Anos 20', 'DELICIAS', 41.65538200, -0.90006300, '0101000020E610000065DEAAEB50CDECBF8C31B08EE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15519093557.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15519093557.webp', 'https://www.flickr.com/photos/zaragozaantigua/15519093557/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23697, 'Paso a nivel Delicias 1915', 'Archivo Municipal. Francisco Gâ”œâ”‚rriz (Donaciâ”œâ”‚n Palacio Fuenclara). 1915. "Retrato de grupo de niâ”œâ–’os". Imagen capturada en el paso a nivel de Delicias, antes de que fuera ensanchado. El tranvâ”œÂ¡a circulaba junto a la acera de enfrente. Poco trâ”œÃ­fico rodado, y sol.', 1915, 1915, 1915, 'Anos 10', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15583773786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15583773786.webp', 'https://www.flickr.com/photos/zaragozaantigua/15583773786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23699, 'Juan XXIII 1984', 'Imagen de la calle Juan XXIII capturada desde la entrada por la Avenida de Madrid, con visual (a la izquierda) de la casa-asilo para sacerdotes que el Arzobispo prestâ”œâ”‚ en el barrio de Delicias a los PP. Carmelitas Descalzos y que fue su base de operaciones desde febrero de 1897 hasta enero de 1944, en que se trasladaron a la nueva parroquia de la calle San Juan de la Cruz. A finales de los aâ”œâ–’os 80 del pasado siglo, el edificio fue piqueteado, y en su lugar se construyeron las nuevas instalaciones del IES "El Portillo", que se vino aquâ”œÂ¡ desde las antiguas instalaciones del Colegio de Maristas de San Vicente de Paâ”œâ•‘l. De esta forma, el IES queda justo enfrente del Colegio Pâ”œâ•‘blico Juan XXIII. Fuente visual: "Zaragoza, sus calles y su historia", HA, 1984.', 1984, 1984, 1984, 'Anos 80', 'DELICIAS', 41.65538200, -0.90006300, '0101000020E610000065DEAAEB50CDECBF8C31B08EE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16030415709.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16030415709.webp', 'https://www.flickr.com/photos/zaragozaantigua/16030415709/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23713, 'Paso a nivel Delicias 1913', '"Nuevo paso a nivel recientemente inaugurado en el Castillo de la Aljaferâ”œÂ¡a, de gran interâ”œÂ®s para la lâ”œÂ¡nea de Zaragoza-Navarra". En 1911, al objeto de reducir la peligrosidad del cruce transversal, y a nivel, de la carretera de Madrid y la lâ”œÂ¡nea de ferrocarril de Alsasua, el Ayuntamiento impulsâ”œâ”‚ la construcciâ”œâ”‚n de un paso subterrâ”œÃ­neo "mediante una trinchera suficiente para el paso de carros sin entorpecimiento y obstâ”œÃ­culos". Fue inaugurado en 1912. En la imagen, capturada desde la carretera de Madrid, con el cuartel de La Aljaferâ”œÂ¡a a la izquierda, vista de la trinchera del primer paso a nivel de las Delicias. Un buen nâ”œâ•‘meros de "tancredos", y entre ellos no faltan escolares del entorno, comprueban la firmeza del paso. Por abajo, peatones hacia Delicias. Al fondo, el â”œÃ­rea del Portillo. Fuente: Foto Marâ”œÂ¡n, diario "La Crâ”œâ”‚nica".', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25477385870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25477385870.webp', 'https://www.flickr.com/photos/zaragozaantigua/25477385870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23735, 'Paso a nivel Delicias 1912', 'Imagen de las obras de construcciâ”œâ”‚n del nuevo paso a nivel ferroviario de la lâ”œÂ¡nea de Madrid-Zaragoza (p.k. 340,436), sobre el paso inferior de la carretera de Madrid a Francia. En 1911, y al objeto de reducir la creciente peligrosidad del cruce a nivel de la carretera y la lâ”œÂ¡nea de ferrocarril, el Ayuntamiento impulsâ”œâ”‚ la construcciâ”œâ”‚n de este paso subterrâ”œÃ­neo en forma de "trinchera suficiente para el paso de carros sin entorpecimiento y obstâ”œÃ­culos". En este excepcional caso, la trinchera o zanja no era para uso ferroviario. La imagen ha sido capturada desde la carretera de Madrid, con el cuartel de La Aljaferâ”œÂ¡a a la izquierda y fuera de plano, y algunos inmuebles recayentes a la carretera, a la derecha. Al fondo, ascendente rampa hacia el â”œÃ­rea del Portillo. Desde su privilegiada posiciâ”œâ”‚n en la parte superior, los "tancredos" de turno observan el progreso de las obras.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65526600, -0.89796000, '0101000020E610000095B7239C16BCECBF22179CC1DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48876001528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48876001528.webp', 'https://www.flickr.com/photos/zaragozaantigua/48876001528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23736, 'Ctra. de Madrid c.1893', 'Interesante y poco frecuente imagen capturada desde la Casa-Asilo de Sacerdotes propiedad del Arzobispado sita en el camino de Herederos paralelo a la vâ”œÂ¡a del ferrocarril de Madrid. En primer tâ”œÂ®rmino, el paso a nivel ferroviario de las lâ”œÂ¡nea de Madrid que, en su camino hacia la estaciâ”œâ”‚n de los directos, se cruza con la carretera de Madrid a Francia. A la derecha, el barrio de la Explanada, que culmina al fondo en la gran estructura del Hospicio Provincial y la câ”œâ•‘pula de San Ildefonso. Hacia la izquierda, la iglesia del Portillo, de la que casi emergen la torre de San Pablo Apâ”œâ”‚stol y la recrecida torre de Santiago del templo del Pilar. Algo mâ”œÃ­s hacia la derecha y al fondo, la torre y cimborrio de la Seo, y la Torre Nueva demediada y en inexorable proceso de derribo. Ademâ”œÃ­s pueden verse la torre de Santa Marâ”œÂ¡a Magdalena, San Gil Abad, etc. En 1896 esta Casa-Asilo serâ”œÂ¡a cedida a la Orden de los Carmelitas, que la habilitarâ”œÂ¡an como provisional convento durante varias dâ”œÂ®cadas.', 1893, 1893, 1893, 'Siglo XIX', 'DELICIAS', 41.65530200, -0.89832500, '0101000020E610000002BC051214BFECBF6F8099EFE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49050784196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49050784196.webp', 'https://www.flickr.com/photos/zaragozaantigua/49050784196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23739, 'Paso de Delicias 1923', 'Imagen del paso a nivel ferroviario de Delicias desde la avenida de Madrid. A la izquierda, inmuebles de los nâ”œâ•‘meros 49-55, donde destaca el aserradero de maderas de Gimâ”œÂ®nez y Hernâ”œÃ­ndez. A la derecha, operarios laborando en la torre de agujas y la fachada del convento de los carmelitas descalzos de san Josâ”œÂ®. Al fondo, el barrio de las Delicias. En primer tâ”œÂ®rmino, terroso aspecto de la avenida con la vâ”œÂ¡a â”œâ•‘nica de la lâ”œÂ¡nea Delicias del tranvâ”œÂ¡a, que en 1927 serâ”œÂ¡a desdoblada.', 1923, 1923, 1923, 'Anos 20', 'DELICIAS', 41.65532600, -0.89777800, '0101000020E61000006A2FA2ED98BAECBFF81BEDB8E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51284102729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51284102729.webp', 'https://www.flickr.com/photos/zaragozaantigua/51284102729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23917, 'Vista desde El Portillo c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1874-1877. "Vista general desde el Portillo". Panorâ”œÃ­mica pergeâ”œâ–’ada para la ocasiâ”œâ”‚n, en una composiciâ”œâ”‚n inâ”œÂ®dita, democrâ”œÃ­tica, cientâ”œÂ¡fica y popular, generada en los laboratorios del', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65588700, -0.89301400, '0101000020E610000038D89B189293ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14832053848.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14832053848.webp', 'https://www.flickr.com/photos/zaragozaantigua/14832053848/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23926, 'Plaza del Portillo 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Marzo 1966. Imagen de la celebraciâ”œâ”‚n de la Fiesta de la Guardia Municipal en la plaza del Portillo. Detrâ”œÃ­s de la Policâ”œÂ¡a Montada de Saldudâ”œÃ­, la iglesia del Portillo (con su recuerdo al "Ausente"), y las viviendas a ella anexas, en lo que hoy es calle Monseâ”œâ–’or â”œÃ´scar Ataâ”œâ•‘lfo Romero, y aledaâ”œâ–’os.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15716569715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15716569715.webp', 'https://www.flickr.com/photos/zaragozaantigua/15716569715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23927, 'Agustina de Aragâ”œâ”‚n 1808', 'Litografâ”œÂ¡a de Pâ”œÂ®rez, 1873. Ilustraciâ”œâ”‚n sobre la câ”œÂ®lebre reusina Agustina Zaragoza (1786-1857), que segâ”œâ•‘n la leyenda, prendiâ”œâ”‚ fuego a un caâ”œâ–’â”œâ”‚n a los 22 aâ”œâ–’os en la puerta del Portillo de Zaragoza, ante el ataque francâ”œÂ®s durante los sitios. Fuente: Los Niâ”œâ–’os, revista de educaciâ”œâ”‚n y recreo, octubre de 1873.', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65606200, -0.89276300, '0101000020E6100000EC8502B68391ECBFFD12F1D6F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20040832241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20040832241.webp', 'https://www.flickr.com/photos/zaragozaantigua/20040832241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23930, 'Calle Jesâ”œâ•‘s Muro 1968', '"Discurso durante la inauguraciâ”œâ”‚n de la calle Jesâ”œâ•‘s Muro." La apertura de un nuevo vial entre la plaza del Portillo y el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n dio pie a que el Ayuntamiento decidiera ponerle el nombre del recientemente fallecido Jesâ”œâ•‘s Muro Sevilla, singularizando en el correspondiente azulejo su responsabilidad como jefe de la Falange zaragozana el 18 de julio de 1936. En la imagen, nocturna captura del acto oficial de inauguraciâ”œâ”‚n de la nueva calle, con presencia de miembros de la corporaciâ”œâ”‚n municipal, con el alcalde Cesâ”œÃ­reo Alierta al frente, y "camisas viejas" (+ â”œâ”‚ -) de la Falange local. A los micrâ”œâ”‚fonos, Radio Zaragoza. Al fondo, entre las tinieblas, restos del Cuartel del Cid (izquierda), y la câ”œâ•‘pula y torres del Hogar Pignatelli. Esta calle serâ”œÃ­ redenominada "Marie Curie" en el aâ”œâ–’o 2009.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65489500, -0.89331300, '0101000020E6100000C8EE02250596ECBF2FA86F99D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22480873808.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22480873808.webp', 'https://www.flickr.com/photos/zaragozaantigua/22480873808/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23931, 'Plaza del Portillo 1968', 'Imagen capturada durante la celebraciâ”œâ”‚n oficial del celestial patronazgo ejercido por Nuestra Seâ”œâ–’ora del Portillo sobre la Guardia Municipal de la ciudad, como tradicionalmente venâ”œÂ¡a haciâ”œÂ®ndose desde los aâ”œâ–’os 40 (de ese mismo siglo XX). El lugar son las inmediaciones a la iglesia del Portillo, que queda a la derecha de la imagen. Como fondo escâ”œÂ®nico, el antiguo Cuartel de Caballerâ”œÂ¡a del Cid, desmilitarizado tras la primera fase de la "Operaciâ”œâ”‚n Cuarteles", que ya ha sido limpiamente seccionado para posibilitar la apertura de un nuevo vial entre la plaza del Portillo y el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n (al fondo), vial al que el Ayuntamiento decidiâ”œâ”‚ ponerle el nombre del recientemente fallecido Jesâ”œâ•‘s Muro Sevilla, jefe de la Falange zaragozana el 18 de julio de 1936. En el suelo, entre adoquines, perdura el tendido viario de la desmantelada lâ”œÂ¡nea tranviaria de Madrid. A la derecha, el edificio del nâ”¬â•‘ 5 de la plaza del Portillo. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal)', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65499200, -0.89245500, '0101000020E610000090DAC4C9FD8EECBF219221C7D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23359946661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23359946661.webp', 'https://www.flickr.com/photos/zaragozaantigua/23359946661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23941, 'Plaza del Portillo 1892', 'Imagen capturada desde la altura de la iglesia del Portillo, y centrada en el entorno de esa arbolada plaza. Tras ella, el antiguo coso de la Misericordia, y a su derecha, la Casa Inclusa, y el cuartel de caballerâ”œÂ¡a del Cid. A la izquierda, la calle de Pignatelli y el cuartel de Ingenieros de Sangenis. De fondo, el impresionante Hospicio Provincial, con su neobizantina câ”œâ•‘pula. Hemos volteado horizontalmente la original imagen, y asâ”œÂ¡ se ven mâ”œÃ­s las cosas en su sitio. Fuente visual: Estudio Coyne, AHPZ.', 1892, 1892, 1892, 'Siglo XIX', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30802095414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30802095414.webp', 'https://www.flickr.com/photos/zaragozaantigua/30802095414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23942, 'Portillo 1808', '"La heroâ”œÂ¡na de Zaragoza". â”œÃ´leo sobre lienzo, Marcos Hirâ”œÃ­ldez Acosta, 1871. Representaciâ”œâ”‚n del momento en que Agustina de Aragâ”œâ”‚n prende la mecha de un caâ”œâ–’â”œâ”‚n contra el ejâ”œÂ®rcito francâ”œÂ®s, en los Sitios de Zaragoza. Al fondo a la derecha, la entrada a la ciudad por la puerta del Portillo, anexa a la iglesia homâ”œâ”‚nima, fuera de cuadro. Fuente: web.dpz.es/arscatalogi.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65614900, -0.89383200, '0101000020E6100000E2C80391459AECBFCC26C0B0FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32103983833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32103983833.webp', 'https://www.flickr.com/photos/zaragozaantigua/32103983833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23944, 'El Portillo 1808', '"La defensa de Zaragoza"; â”œâ”‚leo sobre lienzo, David Wilkie, 1828. Agustina de Aragâ”œâ”‚n comparece ante su mâ”œÂ¡tico caâ”œâ–’â”œâ”‚n, presta a dispararlo hacia las afueras de Zaragoza contra el ejâ”œÂ®rcito francâ”œÂ®s. Tras ella, el Portillo propiamente dicho. Fuente: WIkimedia Commons.', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65622400, -0.89352900, '0101000020E6100000F8E12021CA97ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40384270754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40384270754.webp', 'https://www.flickr.com/photos/zaragozaantigua/40384270754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23973, 'Pl. del Portillo c.1962', 'Archivo Municipal de Zaragoza. Archivo fotogrâ”œÃ­fico Editorial Arribas (EDIVIS). Aâ”œâ–’os 60. "Plaza de Toros." Un primer Coso Taurino fue mandado construir por Ramâ”œâ”‚n Pignatelli para conseguir ingresos con que mantener la Casa de la Misericordia. Inaugurado en 1764, era en madera, luego ladrillo, y en 1895, en piedra. La gran reforma de 1916, dirigida por Martinez de Ubago y Miguel Angel Navarro, le dio el aspecto actual. En la imagen, vista panorâ”œÃ­mica de la plaza del Portillo, la plaza de toros, el Cuartel del Cid, La Casa de la Misericordia, la Maternidad e Inclusa de la DPZ, y las casas de militares del Paseo de Mâ”¬Â¬ Agustâ”œÂ¡n.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65537000, -0.89228600, '0101000020E61000008DB7955E9B8DECBFC763062AE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181301378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181301378.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181301378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
