INSERT INTO public.photos VALUES (24176, 'Paso a nivel Delicias c.1966', '"Paso a desnivel". Colecciâ”œâ”‚n Paco Boisset Locomotora a vapor tirando de un convoy en el paso a nivel de Las Delicias, viviendo de la estaciâ”œâ”‚n Campo Sepulcro (al fondo). Por debajo pasa la avenida de Madrid.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15007240298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15007240298.webp', 'https://www.flickr.com/photos/zaragozaantigua/15007240298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
