INSERT INTO public.photos VALUES (24509, 'Jabones Nicolâ”œÃ­s c.1955', 'Vista de la entrada de la antigua fâ”œÃ­brica de Jabones Nicolâ”œÃ­s, poco despuâ”œÂ®s de que este mismo espacio fuese ocupado por la fâ”œÃ­brica de muebles de alta gama Simâ”œâ”‚n Loscertales Bona, en la calle Aljaferâ”œÂ¡a, donde terminaba la calle Comandante Rodrâ”œÂ¡guez de Câ”œâ”‚rdoba (desde 2009, Sebastiâ”œÃ­n Banzo Urrea).', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65708700, -0.89476500, '0101000020E6100000C45F9335EAA1ECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32061267736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32061267736.webp', 'https://www.flickr.com/photos/zaragozaantigua/32061267736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24519, 'Calle del Trovador 1945', 'Posado de trabajadores de la fâ”œÃ­brica de gaseosas Anastasio Jimâ”œÂ®nez, comercializadora de gaseosas y sifones Tasio, ante la entrada de la factorâ”œÂ¡a, en el nâ”œâ•‘mero 11 de la calle del Trovador. Tras el carruaje de la derecha, acceso cerrado a lo que luego serâ”œÃ­ la prolongaciâ”œâ”‚n de la calle de Jerâ”œâ”‚nimo Borao (hasta mediados los sesenta, callejâ”œâ”‚n), que parte del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. Perdura el inmueble. El de la derecha, no. Fuente visual: Asociaciâ”œâ”‚n Paso a nivel.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65509900, -0.89538500, '0101000020E6100000D7868A71FEA6ECBF3752B648DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38319990051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38319990051.webp', 'https://www.flickr.com/photos/zaragozaantigua/38319990051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
