INSERT INTO public.photos VALUES (24555, 'La Aljaferâ”œÂ¡a 1848', '"Aljaferâ”œÂ¡a de Zaragoza", xilografâ”œÂ¡a de Ildefonso Cibera para la Historia general de Espaâ”œâ–’a, Madrid, 1848. Se pueden ver la torre de la capilla de San Martâ”œÂ¡n, el tejado a dos vertientes de la cubierta torre del Homenaje, y la contraescarpa del foso, del remozado recinto en los finales del XVIII, como cuartel del ejâ”œÂ®rcito. Fuente visual: â”œÃ¼lbum grâ”œÃ­fico de Zaragoza, 1985.', 1848, 1848, 1848, 'Siglo XIX', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19499093442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19499093442.webp', 'https://www.flickr.com/photos/zaragozaantigua/19499093442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24556, 'Av. de Madrid 1979', 'Imagen de uno de los edificios promovidos por el emprendedor â”œÃ¼ngel Colmenero Criado, en este caso, por medio de la empresa "PROCANSA" (Promotora Inmobiliaria Câ”œÃ­ntabro Pirenaica S. A.), en la Avenida de Madrid 7, una promociâ”œâ”‚n de 117 viviendas, con un "Gran Pasaje Comercial", "Oficinas", y "Tres plantas de Garajes". Las condiciones de compra se anunciaban inmejorables, con "Mâ”œÂ¡nimas entradas", y "Resto, grandes facilidades". No era para menos, ya que este emprendedor tenâ”œÂ¡a la costumbre de hacer mâ”œÃ­s alturas de las legalmente autorizadas, y venderlas como si nada. El aâ”œâ–’o de la imagen, precisamente, fue procesado por reiteradas irregularidades en las promociones que impulsaba, como en el sonado caso del "Edificio Venus" del Paseo General Mola 62, y otros mâ”œÃ­s, en San Juan de la Peâ”œâ–’a, Paseo de las Damas, y este de la Avenida de Madrid. Un par de aâ”œâ–’os antes, durante la â”œâ•‘ltima corporaciâ”œâ”‚n franquista, este emprendedor interpuso una querella al Colegio de Arquitectos para defender su honor de las denuncias de que construâ”œÂ¡a mâ”œÃ­s alturas de las autorizadas. Mientras tanto, el Ayuntamiento hacâ”œÂ¡a como que paralizaba las obras, pero en la prâ”œÃ­ctica estas continuaban. En 1979, la primera corporaciâ”œâ”‚n de la recuperada democracia municipal derribâ”œâ”‚ una obra ilegal promovida por este emprendedor en la calle Jerâ”œâ”‚nimo Borau, precisamente en las traseras del complejo que estaba construyendo en la Avenida de Madrid. Este era el aspecto de la obra de la Avenida de Madrid. Algunas pintadas aluden al personaje referido. En 1982 esta promociâ”œâ”‚n estarâ”œÂ¡a finalizada. A su izquierda, los veteranos edificios del nâ”¬â•‘ 3-5, donde Casa Emilio. Imagen obtenida desde la calle Comandante Rodrâ”œÂ¡guez de Câ”œâ”‚rdoba, desde 2009 denominada Sebastiâ”œÃ­n Banzo Urrea, primer alcalde constitucional de Zaragoza durante la Segunda Repâ”œâ•‘blica. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”œâ•‘blico Municipal.', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65569500, -0.89457000, '0101000020E61000007172BF4351A0ECBF4B9352D0EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19996019222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19996019222.webp', 'https://www.flickr.com/photos/zaragozaantigua/19996019222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
