INSERT INTO public.photos VALUES (24560, 'La Aljaferâ”œÂ¡a 1627', 'Plano de la Aljaferâ”œÂ¡a de Zaragoza, con indicaciâ”œâ”‚n del lugar que ocupaba la sede de la Inquisiciâ”œâ”‚n, 1627. Este plano fue datado por Pedro I. Sobradiel en 2009. Incluye, superpuestos, unos papeles con las fachadas del patio de San Martâ”œÂ¡n, lugar que ocupaba la Inquisiciâ”œâ”‚n tras la fortificaciâ”œâ”‚n del edificio en 1593, habiendo sido anteriormente todo el edificio propiedad de ese tribunal. Fuente: servicios3.aragon.es/bva/i18n/catalogo_imagenes/grupo.cmd...', 1627, 1627, 1627, 'Siglo XIX', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23808862353.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23808862353.webp', 'https://www.flickr.com/photos/zaragozaantigua/23808862353/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24561, 'La Aljaferâ”œÂ¡a 1708', '"Plano del castillo de la Inquisiciâ”œâ”‚n, cerca de Zaragoza, capital del reino de Aragâ”œâ”‚n en Espaâ”œâ–’a, en el estado en que estaba en 1708", por el ingeniero francâ”œÂ®s Claude Massâ”œÂ®. Se trata de uno de los varios proyectos teâ”œâ”‚ricos de fortificaciâ”œâ”‚n del castillo de la Aljaferâ”œÂ¡a durante la guerra de Sucesiâ”œâ”‚n espaâ”œâ–’ola. Fuente visual: Pedro I. Sobradiel, El castillo de la Aljaferâ”œÂ¡a: 1600-1800. de medieval a ilustrado, IEIOP, Zaragoza, 2009.', 1708, 1708, 1708, 'Siglo XIX', 'DELICIAS', 41.65656600, -0.89697300, '0101000020E6100000E8A38CB800B4ECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24118516037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24118516037.webp', 'https://www.flickr.com/photos/zaragozaantigua/24118516037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24562, 'La Aljaferâ”œÂ¡a 1592', '"Traza del castillo que se ha de hacer en la Aljaferâ”œÂ¡a de Zaragoza", Tiburcio Spanochi, 1592. En 1592, Felipe II proyectâ”œâ”‚ varias obras de fortificaciâ”œâ”‚n de la ciudad de Zaragoza, a raâ”œÂ¡z de los altercados sucedidos desde 1591. De todas ellas, sâ”œâ”‚lo se realizâ”œâ”‚ la transformaciâ”œâ”‚n del Palacio de la Aljaferâ”œÂ¡a en castillo fortificado. En el plano, la Aljaferâ”œÂ¡a, el râ”œÂ¡o Ebro, la Puerta Sancho, la Puerta del Portillo y la iglesia del Portillo. Fuente: Archivo General de Simancas.', 1592, 1592, 1592, 'Siglo XIX', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24352922561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24352922561.webp', 'https://www.flickr.com/photos/zaragozaantigua/24352922561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
