INSERT INTO public.photos VALUES (24564, 'Motâ”œÂ¡n de Zaragoza 1591', 'Ã”Ã‡Â£Las alteraciones de Aragâ”œâ”‚n. Motâ”œÂ¡n de Zaragoza, 1591Ã”Ã‡Ã˜. Grabado del siglo XIX coloreado posteriormente. En 1591 se produjeron ciertas algaradas en las calles de Zaragoza, que la historiografâ”œÂ¡a dio en ubicar en diversos entornos urbanos. Uno de estos pretendidos motines habrâ”œÂ¡a tenido lugar en la Aljaferâ”œÂ¡a, donde fue trasladado Antonio Pâ”œÂ®rez provisionalmente; la ilustraciâ”œâ”‚n quizâ”œÃ­s pretende reflejar ese entorno, sin demasiado acierto. Fuente visual: www.alamy.es', 1591, 1591, 1591, 'Siglo XIX', 'DELICIAS', 41.65671000, -0.89669400, '0101000020E61000001F9F909DB7B1ECBF637AC2120FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41057293392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41057293392.webp', 'https://www.flickr.com/photos/zaragozaantigua/41057293392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
