INSERT INTO public.photos VALUES (24923, 'Plaza del Portillo 1908', 'Foto: Freudenthal. Inauguraciâ”œâ”‚n del monumento a Agustina de Aragâ”œâ”‚n en la plaza del Portillo, por parte de Alfonso XIII y Victoria Eugenia, el 29 de octubre de 1908. Al fondo, iglesia del Portillo. Fuente: La ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana, a travâ”œÂ®s de www.facebook.com/photo.php?fbid=1205203256182307&set=...', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65565200, -0.89243700, '0101000020E6100000F7B0170AD88EECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33245875235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33245875235.webp', 'https://www.flickr.com/photos/zaragozaantigua/33245875235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24926, 'Plaza del Portillo 1908', 'El escultor Mariano Benlliure, inspeccionando su monumento a Agustina de Aragâ”œâ”‚n en la plaza del Portillo, en octubre de 1908. Serâ”œÃ­ inaugurado por los reyes el 29 del mismo mes. Fuente: Foto Moya. Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65565200, -0.89243700, '0101000020E6100000F7B0170AD88EECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41188191021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41188191021.webp', 'https://www.flickr.com/photos/zaragozaantigua/41188191021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25098, 'Victoria Eugenia 1908', 'Foto: Goâ”œâ–’i. La reina Victoria Eugenia y su marido Alfonso XIII inauguran el monumento a Agustina de Aragâ”œâ”‚n en la plaza del Portillo, el 29 de octubre de 1908. Fuente: Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65569200, -0.89243500, '0101000020E6100000C9C859D8D38EECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40292986515.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40292986515.webp', 'https://www.flickr.com/photos/zaragozaantigua/40292986515/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25103, 'Calle del Portillo 1908', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 33 del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n y centrada en el cortejo del rey Alfonso XIII que, acompaâ”œâ–’ado del alcalde y de los infantes Fernando y Luis Alfonso y proveniente del coso de la Misericordia, se dirige al recinto de la Exposiciâ”œâ”‚n Hispano-Francesa para visitarlo. A la izquierda, los muros perimetrales de la gran huerta del convento de Santa Inâ”œÂ®s. A la derecha, la iglesia de Nuestra Seâ”œâ–’ora del Portillo. Al fondo y en el centro, inmueble de la antigua Casa de la Galera esquinera entre la calle de Santa Inâ”œÂ®s y la calle del Portillo. Al fondo y a la izquierda, vista parcial de la torre de San Pablo Apâ”œâ”‚stol, y la torre de la Seo algo mâ”œÃ­s a la derecha. En primer tâ”œÂ®rmino y sobre el firme, tendido de la lâ”œÂ¡nea de Madrid del tranvâ”œÂ¡a, curvea hacia la derecha y la estaciâ”œâ”‚n de Campo sepulcro o del Mediodâ”œÂ¡a. Esta fue la primera de las dos veces que el jefe del Estado acudiâ”œâ”‚ a Zaragoza este aâ”œâ–’o. Asâ”œÂ¡, el dâ”œÂ¡a 14 de junio, acudiâ”œâ”‚ para asistir a diversas celebraciones memorialistas en las que inaugurâ”œâ”‚ lâ”œÃ­pidas dedicadas a Josâ”œÂ® Palafox en la homâ”œâ”‚nima calle; al Tâ”œÂ¡o Jorge o Jorge Ibort en la homâ”œâ”‚nima calle del Arrabal; a Basilio Boggiero, Santiago Sas y el barâ”œâ”‚n de Warsage en el puente de Piedra; a Antonio de Torres en la calle de Don Jaime I; a la condesa de Bureta en la calle de la Torre Nueva; a Pedro Marâ”œÂ¡a Ric en la Audiencia Provincial; finalmente, el Monumento al Reducto del Pilar no pudo ser inaugurado porque no estaba terminado. Por la tarde, el Rey fue a la plaza de toros a ver al torero Lagartijo torear miuras. En el tercer toro y aprovechando que el Lagartijo recibiâ”œâ”‚ un varetazo, el Rey abandonâ”œâ”‚ la plaza para, como muestra la imagen, encaminarse hacia el recinto de la exposiciâ”œâ”‚n Hispano-Francesa.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65617600, -0.89360400, '0101000020E6100000A164726A6798ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50629504571.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50629504571.webp', 'https://www.flickr.com/photos/zaragozaantigua/50629504571/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25855, 'Calle del Conde de Aranda c.1994', 'Desde el inmueble del nâ”¬â•‘ 126 de la calle del Conde Aranda recayente a la plaza del Portillo, un vistazo en altura al tramo final de esa calle centrado en el denso trâ”œÃ­fico direccionado hacia el estratâ”œÂ®gico cruce con el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n y el arranque de la avenida de Madrid. Al fondo, solar en obra donde estuviera el antiguo nâ”¬â•‘ 83 de este paseo y el nâ”¬â•‘ 2 de la calle del Castillo, donde poco despuâ”œÂ®s se levantarâ”œÂ¡a el actual y chaflanero nâ”¬â•‘ 2 de esa calle.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65618400, -0.89330400, '0101000020E6100000FB592C45F295ECBF49145AD6FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50497334301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50497334301.webp', 'https://www.flickr.com/photos/zaragozaantigua/50497334301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25897, 'Paseo Marâ”œÂ¡a Agustâ”œÂ¡n c.1955', 'Cuesta del tramo del paseo Marâ”œÂ¡a Agustâ”œÂ¡n entre la Puerta de Sancho y el Portillo (al fondo). Distintos medios de transporte, entre ellos un tranvâ”œÂ¡a de la lâ”œÂ¡nea 7 "Ayuntamiento-Portillo". Fuente: www.facebook.com/photo.php?fbid=1574816756079888&set=...', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65718000, -0.89336300, '0101000020E6100000399B8E006E96ECBFEACA67791ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15225868337.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15225868337.webp', 'https://www.flickr.com/photos/zaragozaantigua/15225868337/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25935, 'La Ajaferâ”œÂ¡a c.1956', 'Imagen capturada desde la altura del antiguo inmueble del nâ”¬â•‘ 21 de la avenida de Madrid, casi esquinero con el arranque de la calle del Trovador, y centrada en el cuartel de La Aljaferâ”œÂ¡a con el que confrontaba. En primer tâ”œÂ®rmino, remolque de una composiciâ”œâ”‚n tranviaria de la serie 100 en servicio en la lâ”œÂ¡nea 5 Torrero-Delicias encaminada hacia este barrio. Tras ella, jardines con que se habâ”œÂ¡an hermoseado los terraplenes de acceso al cuartel, del que emergen la mole de la torre del Trovador, y la torrecilla de la iglesia de San Martâ”œÂ¡n. A la derecha, instalaciones fabriles de la Industrial Quâ”œÂ¡mica de Zaragoza.', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65595200, -0.89602900, '0101000020E61000000C90680245ACECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49495637613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49495637613.webp', 'https://www.flickr.com/photos/zaragozaantigua/49495637613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22529, 'Cabezo de Buena Vista 1972', 'La serie de tranvâ”œÂ¡as "80" entrâ”œâ”‚ en servicio en 1933, aunque hasta 1937 quedaron en cocheras. Con un remolque jardinera, comenzâ”œâ”‚ ese aâ”œâ–’o en la lâ”œÂ¡nea 11 "Parque", y en 1947 es asignado a la Lâ”œÂ¡nea 5 "Torrero-Delicias", luego "Venecia-Delicias". En noviembre de 1971 esta Lâ”œÂ¡nea fue suprimida. Fue adquirido por el Ayuntamiento para instalarlo en el Cabezo de Buena Vista como Biblioteca Infantil, como recoge la imagen. En 1980 fue definitivamente desguazado. Fuente visual: www.flickr.com/photos/jhm0284/5812535645/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63226000, -0.89374900, '0101000020E610000083A5BA809799ECBFD4484BE5EDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14705380058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14705380058.webp', 'https://www.flickr.com/photos/zaragozaantigua/14705380058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21485, 'Estaciâ”œâ”‚n de Cariâ”œâ–’ena 1926', '1926. La necesidad de contar con un ferrocarril por el que transportar la producciâ”œâ”‚n vitivinâ”œÂ¡cola de Cariâ”œâ–’ena para su exportaciâ”œâ”‚n a Francia, fue el principal motor de la creaciâ”œâ”‚n del ferrocarril de Cariâ”œâ–’ena a Zaragoza. Fue inaugurado el 10 de agosto de 1887, con un servicio regular de trenes consistente en dos convoyes mixtos diarios de ida y vuelta, que perdurarâ”œÂ¡an hasta 1933, aâ”œâ–’o en que esta lâ”œÂ¡nea fue clausurada y subsumida en la de Caminreal. Pese a su cercanâ”œÂ¡a a Campo Sepulcro, la conexiâ”œâ”‚n entre ambas estaciones era complicada, por la notable diferencia de altura entre una y otra. Hubo que trazar un amplio ramal de enlace entre el "Barrio de la Romareda" (actual calle Vicente Berdusâ”œÃ­n y Escoriaza y Fabro) y el "Barrio de La Explanada" (a la izquierda de la carretera de Madrid), hasta llegar a un muelle intercambiador cerca del Paso a Nivel de Delicias. En la imagen, estaciâ”œâ”‚n de Cariâ”œâ–’ena en Zaragoza, con un convoy mixto (plataformas para mercancâ”œÂ¡as+vagones de viajeros) tirado por la locomotora a vapor nâ”¬â•‘ 2, denominada "Pilar". Al fondo, el ampliado edificio central de la estaciâ”œâ”‚n, derribado a principios de los aâ”œâ–’os 50.', 1926, 1926, 1926, 'Anos 20', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14998663245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14998663245.webp', 'https://www.flickr.com/photos/zaragozaantigua/14998663245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
